// src/components/ai/AIWritingAssistant.jsx
// Feature 2: Analyses draft and gives score, tone, strengths, improvements
import { useState } from "react";
import { analyzeWriting } from "../../ai/aiService";

const SENTIMENT_COLORS = {
  Positive: "#059669", Neutral: "#64748b", Negative: "#dc2626",
};
const TONE_ICONS = {
  Professional: "👔", Casual: "😊", Technical: "⚙️",
  Inspirational: "🌟", Conversational: "💬",
};
const READ_COLORS = {
  Easy: "#059669", Medium: "#d97706", Advanced: "#dc2626",
};

export default function AIWritingAssistant({ title, content }) {
  const [result, setResult]   = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError]     = useState("");
  const [open, setOpen]       = useState(false);

  const handleAnalyze = async () => {
    if (!title.trim() || !content.trim()) {
      setError("Please write a title and some content first."); return;
    }
    setLoading(true); setError(""); setOpen(true);
    try {
      const data = await analyzeWriting(title, content);
      setResult(data);
    } catch (e) {
      setError("Analysis failed. Please try again.");
    }
    setLoading(false);
  };

  const score = result?.score || 0;
  const scoreColor = score >= 8 ? "#059669" : score >= 6 ? "#d97706" : "#dc2626";

  return (
    <div style={s.wrap}>
      {/* Trigger button */}
      <button style={s.triggerBtn} onClick={handleAnalyze} disabled={loading}
        onMouseEnter={(e) => e.currentTarget.style.background = "#1e40af"}
        onMouseLeave={(e) => e.currentTarget.style.background = "#1d4ed8"}>
        {loading
          ? <><span style={s.spinner} /> Analysing your writing…</>
          : <><span>🤖</span> AI Writing Assistant</>}
      </button>

      {error && <div style={s.error}>{error}</div>}

      {/* Results panel */}
      {open && result && !loading && (
        <div style={s.panel}>
          <div style={s.panelHeader}>
            <span style={s.panelTitle}>✨ Writing Analysis</span>
            <button style={s.closeBtn} onClick={() => setOpen(false)}>✕</button>
          </div>

          {/* Score + meta row */}
          <div style={s.metaRow}>
            {/* Score circle */}
            <div style={s.scoreCircle}>
              <svg viewBox="0 0 36 36" style={{ width: 80, height: 80 }}>
                <circle cx="18" cy="18" r="15.9" fill="none"
                  stroke="#e2e8f0" strokeWidth="2.5" />
                <circle cx="18" cy="18" r="15.9" fill="none"
                  stroke={scoreColor} strokeWidth="2.5"
                  strokeDasharray={`${score * 10} 100`}
                  strokeLinecap="round"
                  transform="rotate(-90 18 18)" />
              </svg>
              <div style={s.scoreInner}>
                <span style={{ ...s.scoreNum, color: scoreColor }}>{score}</span>
                <span style={s.scoreDen}>/10</span>
              </div>
            </div>

            {/* Tone + readability */}
            <div style={s.metaRight}>
              <div style={s.metaItem}>
                <span style={s.metaLabel}>Tone</span>
                <span style={s.metaVal}>
                  {TONE_ICONS[result.tone] || "📝"} {result.tone}
                </span>
              </div>
              <div style={s.metaItem}>
                <span style={s.metaLabel}>Readability</span>
                <span style={{ ...s.metaVal, color: READ_COLORS[result.readability] }}>
                  ● {result.readability}
                </span>
              </div>
            </div>
          </div>

          {/* Improved intro */}
          {result.rewrittenIntro && (
            <div style={s.introBox}>
              <div style={s.introLabel}>💡 Suggested Opening</div>
              <p style={s.introText}>"{result.rewrittenIntro}"</p>
              <button style={s.copyBtn}
                onClick={() => navigator.clipboard.writeText(result.rewrittenIntro)}>
                📋 Copy
              </button>
            </div>
          )}

          {/* Strengths + Improvements */}
          <div style={s.listsRow}>
            <div style={s.listBox}>
              <div style={s.listTitle}>✅ Strengths</div>
              {result.strengths?.map((s_, i) => (
                <div key={i} style={s.listItem}>
                  <span style={s.greenDot} />
                  <span style={s.listText}>{s_}</span>
                </div>
              ))}
            </div>
            <div style={s.listBox}>
              <div style={s.listTitle}>🔧 Improvements</div>
              {result.improvements?.map((imp, i) => (
                <div key={i} style={s.listItem}>
                  <span style={s.orangeDot} />
                  <span style={s.listText}>{imp}</span>
                </div>
              ))}
            </div>
          </div>

          <div style={s.poweredBy}>✨ Powered by Claude AI</div>
        </div>
      )}
    </div>
  );
}

const s = {
  wrap: { marginTop: 8 },
  triggerBtn: {
    width: "100%", padding: "11px 0",
    background: "#1d4ed8", color: "#fff",
    border: "none", borderRadius: 10,
    fontFamily: "var(--font-display)", fontWeight: 700, fontSize: "0.9rem",
    cursor: "pointer", transition: "background 0.2s",
    display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
  },
  spinner: {
    width: 16, height: 16, border: "2px solid rgba(255,255,255,0.3)",
    borderTopColor: "#fff", borderRadius: "50%",
    animation: "spin 0.7s linear infinite", display: "inline-block",
  },
  error: {
    background: "#fee2e2", color: "#dc2626", borderRadius: 8,
    padding: "10px 14px", fontSize: "0.83rem",
    fontFamily: "var(--font-display)", fontWeight: 600, marginTop: 8,
  },
  panel: {
    marginTop: 14, background: "var(--bg)",
    border: "1.5px solid var(--border)", borderRadius: 14, padding: "20px 20px 16px",
    animation: "slideDown 0.3s ease",
  },
  panelHeader: {
    display: "flex", alignItems: "center",
    justifyContent: "space-between", marginBottom: 16,
  },
  panelTitle: {
    fontFamily: "var(--font-display)", fontWeight: 800,
    fontSize: "1rem", color: "var(--ink)",
  },
  closeBtn: {
    background: "var(--bg-2)", border: "1px solid var(--border)",
    width: 28, height: 28, borderRadius: "50%",
    fontSize: "0.8rem", cursor: "pointer",
    display: "flex", alignItems: "center", justifyContent: "center",
  },
